#!/usr/bin/perl
use Modern::Perl;
use Data::Dumper;
use HTTP::Request::JSON;
use LWP::UserAgent::JSON;
my $request = HTTP::Request::JSON->new("X-RESTLET",
"https://www.truckersearch.com/v1/alerts");
$request->header( "Accept" => "application/json" );
$request->header( "Content-Type" => "application/json" );
$request->header( "api-token" => "REPLACE_KEY_VALUE" );
my $browser = LWP::UserAgent::JSON->new();
my $response = $browser->request($request);
print Dumper($response->json_content);

import Foundation

let headers = [
  "Accept": "application/json",
  "Content-Type": "application/json",
  "api-token": "REPLACE_KEY_VALUE"
]

var request = NSMutableURLRequest(URL: NSURL(string: "https://www.truckersearch.com/v1/alerts")!,
                                        cachePolicy: .UseProtocolCachePolicy,
                                    timeoutInterval: 10.0)
request.HTTPMethod = "X-RESTLET"
request.allHTTPHeaderFields = headers

let session = NSURLSession.sharedSession()
let dataTask = session.dataTaskWithRequest(request, completionHandler: { (data, response, error) -> Void in
  if (error != nil) {
    println(error)
  } else {
    let httpResponse = response as? NSHTTPURLResponse
    println(httpResponse)
  }
})

dataTask.resume()

